        "id": "69326298",
        "title": "Oat Banana Pancakes",
        "imageUrl": "https://via.placeholder.com/400",
        "link": "https://www.fatsecret.com/recipes/69326298-oat-banana-pancakes/Default.aspx",
        "source": "FatSecret",
        "category": "Breakfast",
        "area": "United States",
        "recipeDescription": "These healthy pancakes are excellent source of fiber and lower sugar alternative. Make ahead of time and store leftover portions in the freezer.",
