        "category": "Pork",
        "area": "United States",
        "recipeDescription": "Acorn squash with diced apple and ground pork, sprinkled with fresh grated Parmesan cheese.",
        "dietType": 1,
        "prepTime": 20,
        "estimatedTime": 110,
        "allergens": [
            2
        ],
        "protein": 153,
        "fat": 117,
        "carb": 115,
