        "title": "Ricotta Green Open Omelet",
        "imageUrl": "https://m.ftscrt.com/static/recipe/f3bf7a2f-f7ec-478c-b8a7-ff61e81450fe.jpg",
        "link": "https://www.fatsecret.com/recipes/ricotta-green-open-omelet/Default.aspx",
